create type public.call_status as enum ('pending','initiating','ringing','in-progress','completed','busy','no-answer','cancelled','failed');
create table public.profiles(id uuid primary key references auth.users(id) on delete cascade,display_name text not null default '',avatar_url text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.user_settings(user_id uuid primary key references auth.users(id) on delete cascade,default_country text not null default 'US' check(char_length(default_country)=2),preferred_microphone_id text,preferred_speaker_id text,theme text not null default 'system' check(theme in ('light','dark','system')),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.calls(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id),destination_e164 text not null check(destination_e164 like '+%'),destination_display text not null,twilio_parent_call_sid text unique,twilio_child_call_sid text unique,status public.call_status not null default 'pending',started_at timestamptz,answered_at timestamptz,ended_at timestamptz,duration_seconds integer check(duration_seconds is null or duration_seconds>=0),price numeric(12,4),price_unit text,error_code text,error_message text,hidden_by_user boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create index calls_user_visible_idx on public.calls(user_id,created_at desc) where not hidden_by_user; create index calls_active_idx on public.calls(user_id) where status in ('pending','initiating','ringing','in-progress');
create table public.usage_limits(user_id uuid primary key references auth.users(id),period_start timestamptz not null,period_end timestamptz not null,calls_started integer not null default 0,connected_seconds integer not null default 0,estimated_cost numeric(12,4) not null default 0,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(period_end>period_start));
create table public.rate_limit_events(id bigint generated always as identity primary key,user_id uuid not null references auth.users(id),event_type text not null check(event_type='call-attempt'),created_at timestamptz not null default now()); create index rate_limit_events_lookup on public.rate_limit_events(user_id,created_at desc);
create function public.touch_updated_at() returns trigger language plpgsql as $$begin new.updated_at=now();return new;end$$; create trigger profiles_touch before update on profiles for each row execute procedure public.touch_updated_at(); create trigger settings_touch before update on user_settings for each row execute procedure public.touch_updated_at(); create trigger calls_touch before update on calls for each row execute procedure public.touch_updated_at();
create function public.create_user_records() returns trigger language plpgsql security definer set search_path=public as $$begin insert into profiles(id,display_name) values(new.id,coalesce(new.raw_user_meta_data->>'display_name',''));insert into user_settings(user_id) values(new.id);return new;end$$;create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.create_user_records();
create function public.prepare_uc8_call(p_user_id uuid,p_destination_e164 text,p_destination_display text,p_per_minute int,p_daily_attempts int,p_daily_seconds int,p_concurrent int) returns public.calls language plpgsql security definer set search_path=public as $$declare result public.calls;begin perform pg_advisory_xact_lock(hashtext(p_user_id::text));if (select count(*) from rate_limit_events where user_id=p_user_id and created_at>now()-interval '1 minute')>=p_per_minute then raise exception 'Call attempt limit reached';end if;if (select count(*) from rate_limit_events where user_id=p_user_id and created_at>=date_trunc('day',now()))>=p_daily_attempts then raise exception 'Daily call attempt limit reached';end if;if (select count(*) from calls where user_id=p_user_id and status in ('pending','initiating','ringing','in-progress'))>=p_concurrent then raise exception 'An active call already exists';end if;if coalesce((select sum(duration_seconds) from calls where user_id=p_user_id and answered_at>=date_trunc('day',now())),0)>=p_daily_seconds then raise exception 'Daily connected-minute limit reached';end if;insert into rate_limit_events(user_id,event_type) values(p_user_id,'call-attempt');insert into calls(user_id,destination_e164,destination_display) values(p_user_id,p_destination_e164,p_destination_display) returning * into result;return result;end$$;
alter table profiles enable row level security;alter table user_settings enable row level security;alter table calls enable row level security;alter table usage_limits enable row level security;alter table rate_limit_events enable row level security;
create policy profile_self on profiles for select using(auth.uid()=id);create policy profile_update_self on profiles for update using(auth.uid()=id) with check(auth.uid()=id);create policy settings_self on user_settings for all using(auth.uid()=user_id) with check(auth.uid()=user_id);create policy calls_select_self on calls for select using(auth.uid()=user_id);create policy calls_hide_self on calls for update using(auth.uid()=user_id) with check(auth.uid()=user_id and hidden_by_user=true);create policy usage_self on usage_limits for select using(auth.uid()=user_id);
revoke all on function public.prepare_uc8_call from public;grant execute on function public.prepare_uc8_call(uuid,text,text,int,int,int,int) to service_role;
